head.script:
/**
 * 오더별 원가율 조회
 * id : op_304_01_50b
 */

// 세션정보 가져오기
scwin.sUserId = $c.data.getMemInfo("userId");
scwin.sUserClsCd = $c.data.getMemInfo("userClsCd");
scwin.sClntNo = $c.data.getMemInfo("clntNo");
scwin.sClntNm = $c.data.getMemInfo("clntNm");
scwin.sLobranCd = $c.data.getMemInfo("lobranCd");

scwin.strFromDate = $c.date.getServerDateTime("yyyyMMdd").substring(0, 8);			// 현재년월일을 구한다.
scwin.strToDate = $c.date.getServerDateTime("yyyyMMdd");	// 현재일자를 구한다.
scwin.strDate = scwin.strFromDate + scwin.strToDate;


scwin.onpageload = async function () {
    //오더종류
    $c.sbm.execute(sbm_odrKndCd);

    var codeOptions1 = [
        {
            method: "getLuxeComboDataNcall",
            param1: "WorkImplementEBC",
            param2: "retriveLobran2CodeList",
            compID: "co_lc_srchLobran"
        }
    ];

    $c.data.setGauceUtil(codeOptions1);

    //공통코드 작업구분(OP190)
    const codeOptions = [
        { grpCd: "OP190", compID: "co_lc_srchWrkClsCd"}
    ];
    $c.data.setCommonCode(codeOptions, scwin.callBackCommonCode);

    // if (co_lc_srchWrkClsCd.getValue() == 'B') {
    //     gr_cntrWrkRslts.setColumnVisible("qty", true);
    //     gr_cntrWrkRslts.setColumnVisible("wt", true);
    //     gr_cntrWrkRslts.setColumnVisible("cbm", true);
    //     gr_cntrWrkRslts.setColumnVisible("cntrSizCd20", false);
    //     gr_cntrWrkRslts.setColumnVisible("cntrSizCd40", false);
    //     gr_cntrWrkRslts.setColumnVisible("cntrSizCd45", false);

    // } else {
    //     gr_cntrWrkRslts.setColumnVisible("qty", false);
    //     gr_cntrWrkRslts.setColumnVisible("wt", false);
    //     gr_cntrWrkRslts.setColumnVisible("cbm", false);
    //     gr_cntrWrkRslts.setColumnVisible("cntrSizCd20", true);
    //     gr_cntrWrkRslts.setColumnVisible("cntrSizCd40", true);
    //     gr_cntrWrkRslts.setColumnVisible("cntrSizCd45", true);
    // }

    //co_lc_srchLobran.setSelectedIndex(0);

    //전체조건 추가
    var sLoUpperLobranCd = scwin.sLobranCd;

    //if (co_lc_srchLobran.IndexOfColumn("lobranCd", sLoUpperLobranCd) > 0) {
    if (true) {
        co_lc_srchLobran.setValue(sLoUpperLobranCd);

    } else {
        co_lc_srchLobran.setSelectedIndex(0);
    }

    co_lc_srchLobran.focus();

};

scwin.callBackCommonCode = function() {
    dlt_commonCodeOP190.sort("cd", 0);
    var jsonData1 = dlt_commonCodeOP190.getAllJSON();
    dlt_cmOP190.setJSON(jsonData1);

    $p.setTimeout(function () {
        co_lc_srchWrkClsCd.setSelectedIndex(1);
    }, 1000);
};


scwin.onUdcCompleted = function () {
    ed_srchWrkStDt.setValue(scwin.strToDate);
    ed_srchWrkEndDt.setValue(scwin.strToDate);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    if (chk_retrvStpYn.getValue() == 1) {
        if (ed_bilgClntNo.getValue() == "") {
            $c.win.alert("화주별 조회 선택시 청구화주는 필수 입력항목입니다.");
            return false;
        }
    }else{
        co_lc_srchLobran.setMandatory(false);
    }

    ds_cntrWrkRslts.removeAll();    

    let chk = await $c.gus.cfValidate([tbl_search]);
    if (!chk) {return;}

    if (!$c.gus.cfIsAfterDate(ed_srchWrkStDt.getValue(), ed_srchWrkEndDt.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_srchWrkStDt.focus();
        return;
    }


    $c.sbm.execute(sbm_retreive);

};


scwin.f_filter = function (info) {
    if (info.newValue == 1) {
        co_lc_srchLobran.setMandatory(false);
        co_lc_srchLobran.setDisabled(true);
        ed_bilgClntNo.setMandatory(true);
    } else {
        co_lc_srchLobran.setMandatory(true);
        co_lc_srchLobran.setDisabled(false);
        ed_bilgClntNo.setMandatory(false);
    }
};


//-------------------------------------------------------------------------
// 조회 조건 Reset
//-------------------------------------------------------------------------
scwin.f_Reset = function () {
    $c.gus.cfInitObjects(tb_searchCondition,null);

    ed_srchWrkStDt.setValue(scwin.strToDate);
    ed_srchWrkEndDt.setValue(scwin.strToDate);
};


//공통팝업 호출
scwin.comm_popup = function ( popKind, paramCd, paramNm) {
    if(popKind=="bil"){//청구화주
        udc_comCodeBilgClnt.cfCommonPopUp(
            scwin.udc_comCodeBilgClnt_callBackFunc, paramCd, paramNm, "T", null, null, null, null, null, null, null, null, null, null, "F", "화주,화주코드,화주명"	
        );
    }else if(popKind=="grpClntAll"){//그룹거래처 돋보기용
        udc_comCodeGrpClnt.cfCommonPopUp(
            scwin.udc_comCodeGrpClnt_callBackFunc, paramCd, paramNm, "F", null, null, null, null, null, null, null, null, null, null, "T", "그룹거래처,코드,코드명"	
        );
    }else if(popKind=="grpClnt"){//그룹거래처
        udc_comCodeGrpClnt.cfCommonPopUp(
            scwin.udc_comCodeGrpClnt_callBackFunc, paramCd, paramNm, "T", null, null, null, null, null, null, null, null, null, null, "F", "그룹거래처,코드,코드명"	
        );
    }else if(popKind=="dpt1"){//출발구간1
        udc_comCodeDpt1.cfCommonPopUp(
            scwin.udc_comCodeDpt1_callBackFunc, paramCd, paramNm, "T", null, null, null, null, null, null, null, null, null, null, "F", "작업장,코드,코드명"	
        );
    }else if(popKind=="dpt2"){//출발구간2
        udc_comCodeDpt2.cfCommonPopUp(
            scwin.udc_comCodeDpt2_callBackFunc, paramCd, paramNm, "T", null, null, null, null, null, null, null, null, null, null, "F", "작업장,코드,코드명"	
        );
    }else if(popKind=="arv1"){//도착구간1
        udc_comCodeArv.cfCommonPopUp(
            scwin.udc_comCodeArv_callBackFunc, paramCd, paramNm, "T", null, null, null, null, null, null, null, null, null, null, "F", "작업장,코드,코드명"	
        );
    }else if(popKind=="arv2"){//도착구간2
        udc_comCodeArv2.cfCommonPopUp(
            scwin.udc_comCodeArv2_callBackFunc, paramCd, paramNm, "T", null, null, null, null, null, null, null, null, null, null, "F", "작업장,코드,코드명"	
        );
    }else if(popKind=="carPic"){//배차담당
        udc_comCodeAlloccarPic.cfCommonPopUp(
            scwin.udc_comCodeAlloccarPic_callBackFunc, paramCd, paramNm, "T", null, null, null, null, null, null, null, null, null, null, "F", null	
        );
    }else if(popKind=="odrPic"){//오더담당
        udc_comCodeUser.cfCommonPopUp(
            scwin.udc_comCodeUser_callBackFunc, paramCd, paramNm, "T", null, null, null, null, null, null, null, null, null, null, "F", null	
        );
    }
};

